// In generateSummary():
private async generateSummary(sources: ContextSource[]): Promise<string> {
  const sourceSummaries = sources
    .map(s => `[${s.source}] ${s.summary}`)
    .join('\n')
  return this.llm.generateText({ system: SUMMARY_SYSTEM_PROMPT, prompt: sourceSummaries })
}

AFTER:
// In merge():
const combinedText = selected
  .map(s => `[${s.source}] ${s.summary}`)
  .join('\n')
const [extractedEntities, activityClassification, summary] = await Promise.all([
  this.extractEntities(combinedText),
  this.classifyActivity(combinedText),
  this.generateSummary(combinedText),  // reuse already-built text
])

// In generateSummary():
private async generateSummary(combinedText: string): Promise<string> {
  return this.llm.generateText({ system: SUMMARY_SYSTEM_PROMPT, prompt: combinedText })
}

WHY: Eliminates the duplicated map/join, reduces generateSummary to a single statement, and makes it clear all three LLM calls receive the same input text.

